#!/usr/bin/env python3
"""Generate the per-language documentation pages under ``docs/languages/``.

The pages are **generated, never hand-edited**, so the supported-OS / supported-version
information cannot drift from the source of truth:

* **OS + example versions** come from each language's matrix JSON
  (``examples/<lang>/<lang>_project_matrix.json``; Python uses
  ``tests/python_project_matrix.json``). Those matrices are what the dynamic-update
  feature maintains, so refreshing them (by hand or via the tooling) and re-running this
  generator keeps the docs in sync.
* **The setup-action snippet** is extracted live from each ``<lang>_test.yml`` workflow
  and rewritten from the SHA pin to the version tag (matching the docs convention that
  ``sync_doc_action_refs.py`` enforces), so a Dependabot action bump flows into the docs.
* **The dynamically-maintained ``stable`` / ``latest``** versions come from the version
  cache (``.github/json2vars-setter/cache/version_cache.json``), which the
  ``Refresh data files`` workflow refreshes from the live release APIs (dynamic update).

Run modes:
* ``python .github/scripts/gen_language_docs.py``         -> (re)write the pages
* ``python .github/scripts/gen_language_docs.py --check``  -> exit 1 if any page is stale

The ``gen-language-docs`` pre-commit hook runs the writer on local commits that touch a
source; ``sync-language-docs.yml`` re-runs it on pushes to ``main``.
"""

from __future__ import annotations

import argparse
import json
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import cast

REPO_ROOT = Path(__file__).resolve().parents[2]
DOCS_DIR = REPO_ROOT / "docs" / "languages"
WORKFLOWS = REPO_ROOT / ".github" / "workflows"
CACHE_FILE = REPO_ROOT / ".github" / "json2vars-setter" / "cache" / "version_cache.json"

REPO_BLOB = "https://github.com/7rikazhexde/json2vars-setter/blob/main"
REPO_TREE = "https://github.com/7rikazhexde/json2vars-setter/tree/main"

GENERATED_MARKER = (
    "<!-- AUTO-GENERATED by .github/scripts/gen_language_docs.py - DO NOT EDIT.\n"
    "     Edit the source matrix JSON / workflow and re-run the generator instead. -->"
)


@dataclass(frozen=True)
class Lang:
    slug: str  # matrix version key == output suffix == strategy prefix
    display: str
    # action repo to locate the setup step in the workflow; None => locate by step name
    action_repo: str | None
    # matrix JSON path relative to the repo root
    matrix: str
    # example project dir relative to the repo root (None => no dedicated example dir)
    example_dir: str | None
    note: str = ""
    # step name fallback when there is no setup action (Kotlin)
    step_name: str = ""


