OS_LABELS = {
    "ubuntu-latest": "Ubuntu",
    "windows-latest": "Windows",
    "macos-latest": "macOS",
}


def load_matrix(rel_path: str) -> tuple[list[str], list[str]]:
    data = json.loads((REPO_ROOT / rel_path).read_text(encoding="utf-8"))
    os_list = list(data.get("os", []))
    versions = data.get("versions", {})
    # the version key is the only key under "versions"
    vlist = next(iter(versions.values())) if versions else []
    return os_list, list(vlist)


_USES_PIN = re.compile(r"^(?P<pre>.*uses:\s*\S+?)@\S+\s+#\s*(?P<ver>\S+)\s*$")


def _rewrite_uses(line: str) -> str:
    """Rewrite ``uses: owner/repo@<sha> # v1.2.3`` -> ``uses: owner/repo@v1.2.3``."""
    m = _USES_PIN.match(line.rstrip())
    if m:
        return f"{m.group('pre')}@{m.group('ver')}"
    return line.rstrip()


def extract_setup_step(lang: Lang) -> str:
    """Pull the language's setup step out of its workflow as a clean YAML snippet."""
    wf = WORKFLOWS / f"{lang.slug}_test.yml"
    lines = wf.read_text(encoding="utf-8").splitlines()

    # locate the anchor line
    idx = None
    if lang.action_repo:
        needle = re.compile(r"uses:\s*" + re.escape(lang.action_repo) + r"@")
        for i, ln in enumerate(lines):
            if needle.search(ln):
                idx = i
                break
    else:
        needle = re.compile(r"-\s*name:\s*" + re.escape(lang.step_name))
        for i, ln in enumerate(lines):
            if needle.search(ln):
                idx = i
                break
    if idx is None:  # pragma: no cover - guards against workflow drift
        raise SystemExit(f"could not locate setup step for {lang.slug} in {wf}")

    # walk back to the start of the list item ("- name:" / "- uses:")
    start = idx
    while start >= 0 and not re.match(r"^\s*-\s", lines[start]):
        start -= 1
    indent = len(lines[start]) - len(lines[start].lstrip())

    # walk forward to the next list item at the same indent
    end = start + 1
    item_at_indent = re.compile(r"^ {" + str(indent) + r"}-\s")
    while end < len(lines) and not item_at_indent.match(lines[end]):
        end += 1

    block = lines[start:end]
    out: list[str] = []
    for ln in block:
        if ln.strip().startswith("#"):  # drop full-line comments
            continue
        ln = _rewrite_uses(ln)
        out.append(ln[indent:] if len(ln) >= indent else ln)
    while out and not out[-1].strip():
        out.pop()
    return "\n".join(out)


def load_cache() -> dict[str, dict[str, object]]:
    if not CACHE_FILE.exists():
        return {}
    data = json.loads(CACHE_FILE.read_text(encoding="utf-8"))
    return cast("dict[str, dict[str, object]]", data.get("languages", {}))


def render_page(lang: Lang, cache: dict[str, dict[str, object]]) -> str:
    os_list, versions = load_matrix(lang.matrix)
    os_rendered = ", ".join(f"`{o}`" for o in os_list)
    os_human = " / ".join(OS_LABELS.get(o, o) for o in os_list)
    versions_json = json.dumps(versions)

    lines: list[str] = []
    lines.append(f"# {lang.display}")
    lines.append("")
    lines.append(GENERATED_MARKER)
    lines.append("")
    lines.append(
        f"How `json2vars-setter` handles {lang.display}, and how the example workflow "
        "provisions it."
    )
    lines.append("")

    # integration table
    lines.append("## json2vars-setter integration")
    lines.append("")
    lines.append("| Item | Value |")
    lines.append("| --- | --- |")
    lines.append(f"| Matrix JSON key | `versions.{lang.slug}` |")
    lines.append(f"| Action output | `versions_{lang.slug}` |")
    lines.append(
        f"| Dynamic-update strategy input | `{lang.slug}-strategy` "
        "(`stable` / `latest` / `both`) |"
    )
    lines.append(
        "| Version source | see [Version Sources](../reference/version-sources.md) |"
    )
    lines.append("")

    # supported runners
    lines.append("## Supported runners")
    lines.append("")
    lines.append(f"The example matrix runs on **{os_human}**:")
    lines.append("")
    lines.append(os_rendered)
    lines.append("")
    lines.append(
        "Any GitHub-hosted runner the setup action supports also works - the OS list is "
        "just the `os` array in your matrix JSON."
    )
    lines.append("")

    # versions
    lines.append("## Supported versions")
    lines.append("")
    lines.append("Example matrix (what the example workflow runs):")
    lines.append("")
    lines.append("```json")
    lines.append(f'"versions": {{ "{lang.slug}": {versions_json} }}')
    lines.append("```")
    lines.append("")

    info = cache.get(lang.slug)
    if info and (info.get("stable") or info.get("latest")):
        lines.append(
            "Latest values tracked by the dynamic-update tooling "
            "(auto-refreshed from the release APIs into the version cache):"
        )
        lines.append("")
        lines.append("| Field | Version |")
        lines.append("| --- | --- |")
        if info.get("stable"):
            lines.append(f"| `stable` | `{info['stable']}` |")
        if info.get("latest"):
            lines.append(f"| `latest` | `{info['latest']}` |")
        lines.append("")
        if info.get("last_updated"):
            lines.append(f"_Cache last updated: {info['last_updated']}._")
            lines.append("")
    else:
        lines.append(
            "> Enable dynamic update (`" + lang.slug + "-strategy`) to have "
            "json2vars-setter fill these in from the latest releases. The "
            "`stable` / `latest` values for this language are populated into the "
            "version cache by the **Refresh data files** workflow."
        )
        lines.append("")

    # setup action
    lines.append("## Setup action (example workflow)")
    lines.append("")
    wf_rel = f".github/workflows/{lang.slug}_test.yml"
    lines.append(
        f"[`{lang.slug}_test.yml`]({REPO_BLOB}/{wf_rel}) provisions {lang.display} "
        "with the matrix value json2vars-setter produced:"
    )
    lines.append("")
    lines.append("```yaml")
    lines.append(extract_setup_step(lang))
    lines.append("```")
    lines.append("")
    if lang.note:
        lines.append(f"> **Note:** {lang.note}")
        lines.append("")

    # references
    lines.append("## References")
    lines.append("")
    if lang.example_dir:
        lines.append(
            f"- Example project: [`{lang.example_dir}/`]({REPO_TREE}/{lang.example_dir})"
        )
    lines.append(f"- Example workflow: [`{wf_rel}`]({REPO_BLOB}/{wf_rel})")
    lines.append(f"- Matrix JSON: [`{lang.matrix}`]({REPO_BLOB}/{lang.matrix})")
    lines.append("")

    return "\n".join(lines)


def render_index() -> str:
    lines: list[str] = []
    lines.append("# Languages")
    lines.append("")
    lines.append(GENERATED_MARKER)
    lines.append("")
    lines.append(
        "Per-language reference: the runners and versions each example exercises, and the "
        "setup action json2vars-setter drives. Supported versions are kept in sync with "
        "the matrix JSON and the dynamic-update version cache - these pages are generated, "
        "not hand-written."
    )
    lines.append("")
    lines.append("| Language | Runners | Setup action |")
    lines.append("| --- | --- | --- |")
    for lang in LANGS:
        os_list, _ = load_matrix(lang.matrix)
        os_human = " / ".join(OS_LABELS.get(o, o) for o in os_list)
        action = f"`{lang.action_repo}`" if lang.action_repo else "direct download"
        lines.append(f"| [{lang.display}]({lang.slug}.md) | {os_human} | {action} |")
    lines.append("")
    return "\n".join(lines)


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--check",
        action="store_true",
        help="exit non-zero if any generated page is out of date (no writes)",
    )
    args = parser.parse_args(argv)

    cache = load_cache()
    # Exactly one trailing newline so the output is stable under end-of-file-fixer.
    targets: dict[Path, str] = {
        DOCS_DIR / "index.md": render_index().rstrip("\n") + "\n"
    }
    for lang in LANGS:
        targets[DOCS_DIR / f"{lang.slug}.md"] = (
            render_page(lang, cache).rstrip("\n") + "\n"
        )

    stale: list[Path] = []
    for path, content in targets.items():
        current = path.read_text(encoding="utf-8") if path.exists() else None
        if current != content:
            stale.append(path)
            if not args.check:
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text(content, encoding="utf-8", newline="\n")

    if args.check and stale:
        rel = ", ".join(str(p.relative_to(REPO_ROOT)) for p in stale)
        print(f"Language docs are out of date: {rel}", file=sys.stderr)
        print("Run: python .github/scripts/gen_language_docs.py", file=sys.stderr)
        return 1
    if not args.check and stale:
        rel = ", ".join(str(p.relative_to(REPO_ROOT)) for p in stale)
        print(f"Updated: {rel}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
